#include <stdio.h>
#include <string.h>
#include <WiFi.h>
#include <HTTPClient.h>

// Configuration constants
#define WIFI_SSID "Your_WiFi_SSID"
#define WIFI_PASSWORD "Your_WiFi_Password"
#define API_SECRET_KEY "Your_API_Secret_Key"
#define API_URL "https://example-cloud-service.com/api/capture"

void connectToWiFi() {
    WiFi.begin(WIFI_SSID, WIFI_PASSWORD);
    while (WiFi.status() != WL_CONNECTED) {
        delay(1000);
        Serial.println("Connecting to WiFi...");
    }
    Serial.println("Connected to WiFi.");
}

void sendDataToCloud(const char* imageData) {
    if (WiFi.status() == WL_CONNECTED) {
        HTTPClient http;
        http.begin(API_URL);
        http.addHeader("Content-Type", "application/json");
        http.addHeader("Authorization", API_SECRET_KEY);

        int httpResponseCode = http.POST(imageData);

        if (httpResponseCode > 0) {
            String response = http.getString();
            Serial.println("Response:");
            Serial.println(response);
        } 
        else {
            Serial.print("Error on sending POST: ");
            Serial.println(httpResponseCode);
        }

        http.end();
    }
    else {
        Serial.println("WiFi not connected");
    }
}

void captureAndUploadImage() {
    // Placeholder for image capture code
    // char* imageData = captureImage();
    char* imageData = "{\"image\":\"data\"}"; // Simulated image data
    sendDataToCloud(imageData);
}

void setup() {
    Serial.begin(115200);
    connectToWiFi();
}

void loop() {
    captureAndUploadImage();
    delay(30000); // Capture and send image every 30 seconds
}